'use client';

import { useState, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { getToken } from '@/lib/api-client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ArrowLeft, Coins, Loader2, Calendar, ChevronLeft, ChevronRight } from 'lucide-react';
interface Transaction {
  id: string;
  amount: number;
  type: string;
  description: string | null;
  workflow_config_id: string | null;
  workflow_name: string | null;
  created_at: string;
}
interface CreditSummary {
  balance: number;
  totalGranted: number;
  totalConsumed: number;
}
export default function UserCreditsPage() {
  const router = useRouter();
  const [token, setToken] = useState<string | null>(null);
  const [summary, setSummary] = useState<CreditSummary>({
    balance: 0,
    totalGranted: 0,
    totalConsumed: 0
  });
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const pageSize = 20;
  useEffect(() => {
    const t = getToken();
    if (t) setToken(t);
  }, []);
  const fetchData = useCallback(async (p: number, sd: string, ed: string) => {
    if (!token) return;
    setLoading(true);
    try {
      const params = new URLSearchParams();
      params.set('page', String(p));
      params.set('pageSize', String(pageSize));
      if (sd) params.set('startDate', sd);
      if (ed) params.set('endDate', ed);
      const res = await fetch(`/api/credits?${params.toString()}`, {
        headers: {
          'x-session': token
        }
      });
      if (res.ok) {
        const data = await res.json();
        setSummary({
          balance: data.balance ?? 0,
          totalGranted: data.totalGranted ?? 0,
          totalConsumed: data.totalConsumed ?? 0
        });
        setTransactions(data.transactions || []);
        setTotal(data.total || 0);
      }
    } catch (e) {
      console.error('fetchData error:', e);
    }
    setLoading(false);
  }, [token]);
  useEffect(() => {
    if (token) fetchData(1, '', '');
  }, [token, fetchData]);
  const handleFilter = () => {
    setPage(1);
    fetchData(1, startDate, endDate);
  };
  const handleClearFilter = () => {
    setStartDate('');
    setEndDate('');
    setPage(1);
    fetchData(1, '', '');
  };
  const totalPages = Math.ceil(total / pageSize);
  const formatAmount = (amount: number) => {
    return amount > 0 ? `+${amount}` : `${amount}`;
  };
  const formatType = (type: string) => {
    const map: Record<string, string> = {
      'admin_grant': '管理员充值',
      'consumption': '工具消耗',
      'activation': '激活赠送',
      'referral': '推广奖励'
    };
    return map[type] || type;
  };
  const formatTime = (dateStr: string) => {
    return new Date(dateStr).toLocaleString('zh-CN', {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit'
    });
  };
  return <div data-inspector-line="119" data-inspector-column="4" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="min-h-screen bg-gray-50">
      <div data-inspector-line="120" data-inspector-column="6" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="max-w-3xl mx-auto px-4 py-6 space-y-6">
        {/* 顶部导航 */}
        <div data-inspector-line="122" data-inspector-column="8" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="flex items-center gap-3">
          <Button data-inspector-line="123" data-inspector-column="10" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" variant="ghost" size="sm" onClick={() => router.push('/dashboard')}>
            <ArrowLeft data-inspector-line="124" data-inspector-column="12" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="w-4 h-4 mr-1" /> 返回
          </Button>
          <h1 data-inspector-line="126" data-inspector-column="10" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-xl font-semibold text-gray-900">积分明细</h1>
        </div>

        {/* 积分概览 */}
        <div data-inspector-line="130" data-inspector-column="8" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="grid grid-cols-3 gap-4">
          <Card data-inspector-line="131" data-inspector-column="10" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx">
            <CardContent data-inspector-line="132" data-inspector-column="12" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="py-4 text-center">
              <div data-inspector-line="133" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-2xl font-bold text-yellow-600">{summary.balance}</div>
              <div data-inspector-line="134" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-xs text-gray-500 mt-1">当前余额</div>
            </CardContent>
          </Card>
          <Card data-inspector-line="137" data-inspector-column="10" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx">
            <CardContent data-inspector-line="138" data-inspector-column="12" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="py-4 text-center">
              <div data-inspector-line="139" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-2xl font-bold text-green-600">+{summary.totalGranted}</div>
              <div data-inspector-line="140" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-xs text-gray-500 mt-1">累计充值</div>
            </CardContent>
          </Card>
          <Card data-inspector-line="143" data-inspector-column="10" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx">
            <CardContent data-inspector-line="144" data-inspector-column="12" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="py-4 text-center">
              <div data-inspector-line="145" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-2xl font-bold text-red-500">-{summary.totalConsumed}</div>
              <div data-inspector-line="146" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-xs text-gray-500 mt-1">累计消耗</div>
            </CardContent>
          </Card>
        </div>

        {/* 时间筛选 */}
        <Card data-inspector-line="152" data-inspector-column="8" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx">
          <CardContent data-inspector-line="153" data-inspector-column="10" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="py-3">
            <div data-inspector-line="154" data-inspector-column="12" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="flex items-center gap-3 flex-wrap">
              <Calendar data-inspector-line="155" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="w-4 h-4 text-gray-400 shrink-0" />
              <Input data-inspector-line="156" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-40 h-9 text-sm" placeholder="开始日期" />
              <span data-inspector-line="163" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-gray-400 text-sm">至</span>
              <Input data-inspector-line="164" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="w-40 h-9 text-sm" placeholder="结束日期" />
              <Button data-inspector-line="171" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" size="sm" onClick={handleFilter}>
                查询
              </Button>
              <Button data-inspector-line="174" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" size="sm" variant="ghost" onClick={handleClearFilter}>
                清除筛选
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* 交易明细列表 */}
        <Card data-inspector-line="182" data-inspector-column="8" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx">
          <CardHeader data-inspector-line="183" data-inspector-column="10" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="pb-3">
            <CardTitle data-inspector-line="184" data-inspector-column="12" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="flex items-center gap-2 text-sm font-medium">
              <Coins data-inspector-line="185" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="h-4 w-4 text-yellow-500" />
              积分流水
              {total > 0 && <span data-inspector-line="188" data-inspector-column="16" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-xs text-gray-400 font-normal ml-2">共 {total} 条记录</span>}
            </CardTitle>
          </CardHeader>
          <CardContent data-inspector-line="192" data-inspector-column="10" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx">
            {loading ? <div data-inspector-line="194" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="flex items-center justify-center py-12">
                <Loader2 data-inspector-line="195" data-inspector-column="16" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="w-6 h-6 animate-spin text-gray-400" />
              </div> : transactions.length === 0 ? <div data-inspector-line="198" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-center py-12 text-gray-400 text-sm">暂无积分记录</div> : <div data-inspector-line="200" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="space-y-1">
                {transactions.map(t => <div data-inspector-line="202" data-inspector-column="18" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" key={t.id} className="flex items-center justify-between py-3 px-3 rounded-lg hover:bg-gray-50 transition-colors">
                    <div data-inspector-line="206" data-inspector-column="20" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="flex-1 min-w-0">
                      <div data-inspector-line="207" data-inspector-column="22" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="flex items-center gap-2">
                        <Badge data-inspector-line="208" data-inspector-column="24" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" variant={t.amount > 0 ? 'default' : 'secondary'} className="text-xs">
                          {formatType(t.type)}
                        </Badge>
                        {t.workflow_name && <span data-inspector-line="212" data-inspector-column="26" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-xs text-gray-400 truncate">{t.workflow_name}</span>}
                      </div>
                      {t.description && <p data-inspector-line="216" data-inspector-column="24" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-xs text-gray-500 mt-1 truncate">{t.description}</p>}
                    </div>
                    <div data-inspector-line="219" data-inspector-column="20" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="flex items-center gap-4 shrink-0 ml-4">
                      <span data-inspector-line="220" data-inspector-column="22" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className={`text-sm font-semibold ${t.amount > 0 ? 'text-green-600' : 'text-red-500'}`}>
                        {formatAmount(t.amount)}
                      </span>
                      <span data-inspector-line="223" data-inspector-column="22" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-xs text-gray-400 w-40 text-right">
                        {formatTime(t.created_at)}
                      </span>
                    </div>
                  </div>)}
              </div>}
          </CardContent>

          {/* 分页 */}
          {totalPages > 1 && <div data-inspector-line="235" data-inspector-column="12" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="flex items-center justify-between px-6 py-3 border-t bg-gray-50 rounded-b-xl">
              <span data-inspector-line="236" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="text-sm text-gray-500">
                第 {page}/{totalPages} 页
              </span>
              <div data-inspector-line="239" data-inspector-column="14" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="flex gap-2">
                <Button data-inspector-line="240" data-inspector-column="16" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" size="sm" variant="outline" disabled={page <= 1} onClick={() => {
              const newPage = page - 1;
              setPage(newPage);
              fetchData(newPage, startDate, endDate);
            }}>
                  <ChevronLeft data-inspector-line="250" data-inspector-column="18" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="w-4 h-4" /> 上一页
                </Button>
                <Button data-inspector-line="252" data-inspector-column="16" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" size="sm" variant="outline" disabled={page >= totalPages} onClick={() => {
              const newPage = page + 1;
              setPage(newPage);
              fetchData(newPage, startDate, endDate);
            }}>
                  下一页 <ChevronRight data-inspector-line="262" data-inspector-column="22" data-inspector-relative-path="src\\app\\dashboard\\credits\\page.tsx" className="w-4 h-4" />
                </Button>
              </div>
            </div>}
        </Card>
      </div>
    </div>;
}